import React from "react";
import "../styles/Professionals.css"; // Ensure this path is correct

const professionals = [
    { id: 1, img: "/images/1.jpg", alt: "Professional 1" },
    { id: 1, img: "/images/2.jpg", alt: "Professional 2" },
    { id: 1, img: "/images/3.jpg", alt: "Professional 3" },
    { id: 1, img: "/images/4.jpg", alt: "Professional 4" },
    { id: 1, img: "/images/5.jpg", alt: "Professional 5" },


];

const Professionals = () => {
    return (
        <section className="professionals-section">
            <h2 className="section-title">OUR PROFESSIONALS</h2>
            <div className="professionals-grid">
                {professionals.map((pro) => (
                    <div key={pro.id} className="diamond">
                        <img src={pro.img} alt={pro.alt} />
                    </div>
                ))}
            </div>
        </section>
    );
};

export default Professionals;
